// 1. Capturamos el HTML crudo entregado por el paso anterior
const htmlPuro = $input.first().json.data;

// Expresión regular elástica: Busca cualquier URL dentro de un href que contenga el patrón exclusivo de los tabulados
const regexZipEnemdu = /href="([^"]*Tabulados_Mercado_Laboral_CSV[^"]*\.zip)"/i;
const coincidencia = htmlPuro.match(regexZipEnemdu);

// Escudo de control de errores: Si el INEC cambia drásticamente la página, se activa la contingencia
if (!coincidencia) {
  throw new Error("Control de Contingencia: No se localizó el patrón 'Tabulados_Mercado_Laboral_CSV' en el portal del INEC.");
}

const urlZipCompleta = coincidencia[1];

// 2. EXTRACCIÓN DINÁMICA DEL PERÍODO FISCAL
// El INEC antepone el año y mes al archivo (ej: 202604_Tabulados...). Capturamos esos 6 dígitos.
const regexPeriodo = /(\d{4})(\d{2})_Tabulados/i;
const matchPeriodo = urlZipCompleta.match(regexPeriodo);

let fechaFiscalFormateada = "";

if (matchPeriodo) {
  const anio = matchPeriodo[1]; // "2026"
  const mes = matchPeriodo[2];  // "04"
  fechaFiscalFormateada = `${anio}-${mes}`; // Resultado homogéneo: "2026-04"
} else {
  // Fallback analítico por si remueven los dígitos del nombre del archivo
  const fechaActual = new Date();
  fechaFiscalFormateada = `${fechaActual.getFullYear()}-${String(fechaActual.getMonth() + 1).padStart(2, '0')}`;
}

// Retornamos el payload preparado para el inyector web y la auditoría
return [{
  json: {
    INDICADOR: "INEC_ENEMDU_TABULADOS",
    FECHA_FISCAL: fechaFiscalFormateada, // ◄--- Dinámica y automatizada (Evita duplicados)
    URL_ZIP_DINAMICO: urlZipCompleta,    // ◄--- La URL real mutada del mes vigente
    ESTADO: "COMPLETO",
    NECESITA_RESPALDO: 0,
    DETALLE_ERROR: ""
  }
}];

// 1. Capturamos el ítem que llega al nodo (con la metadata del error del HTTP que falló)
const rawItem = $input.first().json;
const hoy = new Date();

// 2. Formateamos una fecha de fallback para la FECHA_FISCAL (YYYY-MM-DD)
const anio = hoy.getFullYear();
const mes = String(hoy.getMonth() + 1).padStart(2, '0');
const dia = String(hoy.getDate()).padStart(2, '0');
const fechaFallback = `${anio}-${mes}-${dia}`;

// 3. Extracción molecular y segura del mensaje de error del HTTP anterior
let mensajeError = "Fallo indeterminado en la conectividad con el servidor del INEC.";

if (rawItem.error) {
  mensajeError = rawItem.error.message || JSON.stringify(rawItem.error);
} else if (rawItem.message) {
  mensajeError = rawItem.message;
}

// 4. Retornamos el payload de contingencia estructurado exactamente para Oracle
return [{
  json: {
    INDICADOR: "INEC_ENEMDU_POBLACIONES",
    FECHA_FISCAL: `${fechaFallback}_ERR_ENEMDU`, // Clave única controlada del día para el Upsert
    FECHA_EXTRACCION: hoy,
    ESTADO: "INCOMPLETO",
    NECESITA_RESPALDO: 1, // ◄--- SE ENCIENDE LA BANDERA DE ALERTA EN ORACLE
    DETALLE_ERROR: `Fallo Crítico en Pipeline de Ingesta: ${mensajeError}`.substring(0, 4000),
    DATOS_JSON: JSON.stringify({
      error: true,
      fase: "INGESTA_HTTP_ENEMDU",
      mensaje_tecnico: mensajeError,
      fuente: "Instituto Nacional de Estadística y Censos (INEC)",
      ruta_logica: "INEC/ENEMDU/CONTINGENCIA_ERROR"
    })
  }
}];

// 1. Apuntamos directamente a la llave binaria 'file_1' generada por el nodo Decompress
const archivoPlanoText = await this.helpers.getBinaryDataBuffer(0, 'file_1');

// Soportamos el salto de línea del archivo CSV
const lineas = archivoPlanoText.toString('utf-8').split(/\r?\n/);
const listaFilasProcesadas = [];

// Diccionario para traducir las abreviaturas de meses del INEC a formato numérico estándar
const mesesMap = {
  ene: "01", feb: "02", mar: "03", abr: "04", may: "05", jun: "06",
  jul: "07", ago: "08", sep: "09", oct: "10", nov: "11", dic: "12"
};

// Función para reparar el Mojibake (caracteres rotos por codificación) y limpiar espacios
function sanitizarTextoInec(str) {
  if (!str) return "";
  return str.toString().trim()
    .replace(/Poblacin/g, "Población")
    .replace(/Econmicamente/g, "Económicamente")
    .replace(/aos/g, "años")
    .replace(/rea/g, "Área");
}

// Función para transformar los números con puntos de miles del INEC a enteros puros de JS
function parsearNumeroInec(val) {
  if (val === undefined || val === null) return 0;
  let limpio = val.toString().replace(/[\s\u00A0]/g, '').trim();
  if (limpio === '-' || limpio === '' || limpio === '.-') return 0;
  limpio = limpio.replace(/\./g, ''); // Removemos los puntos de miles
  const num = parseInt(limpio, 10);
  return isNaN(num) ? 0 : num;
}

// Función para normalizar el periodo (ej: "dic-07" -> "2007-12")
function normalizarPeriodoInec(periodoRaw) {
  const partes = periodoRaw.toLowerCase().split('-');
  if (partes.length !== 2) return { texto: "2007-12", anio: 2007, mes: 12 };

  const mesAbrev = partes[0].trim();
  const anioDosDigitos = partes[1].trim();

  const mesNum = mesesMap[mesAbrev] || "12";
  const anioNum = parseInt(anioDosDigitos, 10);

  // Si el año es menor o igual a 50 asumimos siglo XXI (ej: 26 -> 2026), de lo contrario siglo XX
  const anioCuatroDigitos = anioNum <= 50 ? 2000 + anioNum : 1900 + anioNum;

  return {
    texto: `${anioCuatroDigitos}-${mesNum}`,
    anio: anioCuatroDigitos,
    mes: parseInt(mesNum, 10)
  };
}

// Empezamos en la línea 3 para ignorar las filas vacías y de títulos estructurales del CSV
for (let i = 3; i < lineas.length; i++) {
  const filaCruda = lineas[i];
  if (!filaCruda.trim() || filaCruda.startsWith(';')) continue; 

  // Separación por punto y coma (;) típica de los tabulados del INEC
  const celdas = filaCruda.split(';');

  const encuesta = celdas[0] ? celdas[0].trim() : "";
  const periodoRaw = celdas[1] ? celdas[1].trim() : "";
  const indicadorNombre = celdas[2] ? sanitizarTextoInec(celdas[2]) : "";

  // Si no hay indicador válido en la fila, nos la saltamos por seguridad
  if (!indicadorNombre || indicadorNombre.includes("Indicadores")) continue;

  // Procesamos la fecha de forma dinámica
  const fechaDinamica = normalizarPeriodoInec(periodoRaw);

  // Creamos un slug limpio del indicador para construir nuestra FECHA_FISCAL única compuesta
  const slugIndicador = indicadorNombre
    .toLowerCase()
    .replace(/[^a-z0-9]/g, '')
    .substring(0, 25);

  // FECHA_FISCAL COMPUESTA: Combinación perfecta anti-sobreescritura (Ej: "2007-12_poblaciontotal")
  const fechaFiscalClave = `${fechaDinamica.texto}_${slugIndicador}`;

  listaFilasProcesadas.push({
    json: {
      INDICADOR: "INEC_ENEMDU_POBLACIONES",
      FECHA_FISCAL: fechaFiscalClave.substring(0, 150),
      FECHA_EXTRACCION: new Date(),
      ESTADO: "COMPLETO",
      NECESITA_RESPALDO: 0,
      DETALLE_ERROR: "",
      DATOS_JSON: JSON.stringify({
        encuesta: encuesta,
        periodo_original: periodoRaw,
        anio_fiscal: fechaDinamica.anio,
        mes_fiscal: fechaDinamica.mes,
        nombre_indicador: indicadorNombre,
        metricas: {
          nacional_total: parsearNumeroInec(celdas[3]),
          area_urbana:    parsearNumeroInec(celdas[4]),
          area_rural:     parsearNumeroInec(celdas[5]),
          sexo_hombre:    parsearNumeroInec(celdas[6]),
          sexo_mujer:     parsearNumeroInec(celdas[7])
        },
        fuente: "Instituto Nacional de Estadística y Censos (INEC)",
        ruta_logica: "INEC/ENEMDU/TABULADOS_1_POBLACIONES"
      })
    }
  });
}

return listaFilasProcesadas;
